    CONSTRAINT publicacion_estados_pkey PRIMARY KEY (id),
    CONSTRAINT publicacion_estados_nombre_key UNIQUE (nombre)
);

CREATE TABLE IF NOT EXISTS public.publication_authors
(
    id serial NOT NULL,
    publication_id integer NOT NULL,
    author_id integer NOT NULL,
    is_institutional boolean NOT NULL,
    author_position integer,
    role character varying(50) COLLATE pg_catalog."default",
    CONSTRAINT publication_authors_pkey PRIMARY KEY (id),
    CONSTRAINT uq_pub_author UNIQUE (publication_id, author_id)
);

CREATE TABLE IF NOT EXISTS public.reconciliation_log
(
    id serial NOT NULL,
    source_name character varying(50) COLLATE pg_catalog."default" NOT NULL,
    source_record_id integer NOT NULL,
    canonical_publication_id integer,
    match_type character varying(50) COLLATE pg_catalog."default" NOT NULL,
    match_score double precision,
    match_details jsonb,
    action character varying(30) COLLATE pg_catalog."default" NOT NULL,
    created_at timestamp with time zone NOT NULL DEFAULT now(),
    CONSTRAINT reconciliation_log_pkey PRIMARY KEY (id)
);

CREATE TABLE IF NOT EXISTS public.research_thresholds
(
    id serial NOT NULL,
    field_id integer NOT NULL,
    metric_name character varying(50) COLLATE pg_catalog."default" NOT NULL,
    value double precision NOT NULL,
    description text COLLATE pg_catalog."default",
    created_at timestamp with time zone NOT NULL DEFAULT now(),
    CONSTRAINT research_thresholds_pkey PRIMARY KEY (id),
    CONSTRAINT uq_field_metric UNIQUE (field_id, metric_name)
);

COMMENT ON COLUMN public.research_thresholds.metric_name
    IS 'h_alto, h_medio, cpp_alto, cpp_medio, pct_citados, pct_pico, concentracion_limite, ratio_hn_minimo';

CREATE TABLE IF NOT EXISTS public.researcher_credentials
(
    id serial NOT NULL,
    author_id integer NOT NULL,
    password_hash character varying(255) COLLATE pg_catalog."default" NOT NULL,
    is_active boolean NOT NULL DEFAULT true,
    created_at timestamp with time zone NOT NULL DEFAULT CURRENT_TIMESTAMP,
    activated_at timestamp with time zone,
    last_login timestamp with time zone,
    expires_at timestamp with time zone,
    updated_at timestamp with time zone NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT researcher_credentials_pkey PRIMARY KEY (id)
);

CREATE TABLE IF NOT EXISTS public.scopus_records
(
    id serial NOT NULL,
    scopus_doc_id character varying(100) COLLATE pg_catalog."default",
    volume character varying(50) COLLATE pg_catalog."default",
    issue character varying(50) COLLATE pg_catalog."default",
    page_range character varying(100) COLLATE pg_catalog."default",
    abstract text COLLATE pg_catalog."default",
    author_keywords text COLLATE pg_catalog."default",
    dedup_hash character varying(64) COLLATE pg_catalog."default",
    doi character varying(255) COLLATE pg_catalog."default",
    title text COLLATE pg_catalog."default",
    normalized_title text COLLATE pg_catalog."default",
    publication_year integer,
    authors_text text COLLATE pg_catalog."default",
    normalized_authors text COLLATE pg_catalog."default",
    publication_date character varying(20) COLLATE pg_catalog."default",
    publication_type character varying(100) COLLATE pg_catalog."default",
    source_journal character varying(500) COLLATE pg_catalog."default",
    issn character varying(20) COLLATE pg_catalog."default",
    language character varying(10) COLLATE pg_catalog."default",
    is_open_access boolean,
    oa_status character varying(50) COLLATE pg_catalog."default",
    citation_count integer NOT NULL,
    url character varying(1000) COLLATE pg_catalog."default",
    raw_data jsonb,
    status character varying(30) COLLATE pg_catalog."default" NOT NULL,
    match_type character varying(50) COLLATE pg_catalog."default",
    match_score double precision,
    reconciled_at timestamp with time zone,
    created_at timestamp with time zone NOT NULL DEFAULT now(),
    updated_at timestamp with time zone NOT NULL DEFAULT now(),
    canonical_publication_id integer,
    eid character varying(100) COLLATE pg_catalog."default",
    pmid character varying(50) COLLATE pg_catalog."default",
    isbn character varying(30) COLLATE pg_catalog."default",
    index_keywords text COLLATE pg_catalog."default",
    subtype_description character varying(100) COLLATE pg_catalog."default",
    conference_name character varying(500) COLLATE pg_catalog."default",
    funding_agency character varying(300) COLLATE pg_catalog."default",
    funding_number character varying(200) COLLATE pg_catalog."default",
    publisher character varying(300) COLLATE pg_catalog."default",
    journal_coverage character varying(100) COLLATE pg_catalog."default",
    CONSTRAINT scopus_records_pkey PRIMARY KEY (id)
);

COMMENT ON COLUMN public.scopus_records.scopus_doc_id
    IS 'Scopus document ID (dc:identifier sin prefijo)';

COMMENT ON COLUMN public.scopus_records.eid
    IS 'Electronic ID: 2-s2.0-XXXXXXXX';

COMMENT ON COLUMN public.scopus_records.pmid
    IS 'PubMed ID cruzado desde Scopus';

COMMENT ON COLUMN public.scopus_records.isbn
    IS 'ISBN para libros y capítulos de libro';

COMMENT ON COLUMN public.scopus_records.index_keywords
    IS 'Vocabulario controlado de Scopus (idxterms)';

COMMENT ON COLUMN public.scopus_records.subtype_description
    IS 'Article, Review, Conference Paper, Book Chapter, etc.';

COMMENT ON COLUMN public.scopus_records.conference_name
    IS 'Nombre de la conferencia (para conference papers)';

COMMENT ON COLUMN public.scopus_records.funding_agency
    IS 'Entidad financiadora reportada en Scopus';

COMMENT ON COLUMN public.scopus_records.funding_number
    IS 'Número o código del grant de financiación';

CREATE TABLE IF NOT EXISTS public.users
(
