COMMENT ON COLUMN public.wos_records.wos_uid
    IS 'WoS UID, ej: WOS:000123456789';

COMMENT ON COLUMN public.wos_records.accession_number
    IS 'Número de acceso interno WoS';

COMMENT ON COLUMN public.wos_records.early_access_date
    IS 'Fecha de publicación anticipada (Early Access)';

COMMENT ON COLUMN public.wos_records.issn_electronic
    IS 'ISSN de la versión electrónica';

COMMENT ON COLUMN public.wos_records.wos_categories
    IS 'Categorías Web of Science separadas por "; "';

COMMENT ON COLUMN public.wos_records.research_areas
    IS 'Áreas de investigación WoS separadas por "; "';

COMMENT ON COLUMN public.wos_records.times_cited_all_databases
    IS 'Citas contadas en todas las colecciones WoS';

COMMENT ON COLUMN public.wos_records.citing_patents_count
    IS 'Número de patentes que citan este artículo';

COMMENT ON COLUMN public.wos_records.funding_orgs
    IS '[{organization, grant_numbers:[]}]';

